pub fn remove(&mut self, offset: usize) -> T {
    assert!(offset < self.len, "Offset out of bounds");

    let elem: T;
    let last_elem: T;
    let elem_ptr: *mut T;
    let last_elem_ptr: *mut T;

    unsafe {
        elem_ptr = self.mem.offset(offset as isize);
        last_elem_ptr = self.mem.offset(self.len as isize);

        elem = ptr::read(elem_ptr);
        last_elem = ptr::read(last_elem_ptr);

        ptr::write(elem_ptr, last_elem);
    }

    self.len -= 1;
    return elem;
}

fn set_len(&mut self, len: usize) -> Result<(), Error> {
    let additional_elements = isize::try_from(len)
        .and_then(|len| isize::try_from(self.len()).map(|self_len| len - self_len))
        .map_err(|_| Error::SizeLimitExceeded)?;

    // If len == self.len there's nothing to do.
    if additional_elements == 0 {
        return Ok(());
    }

    // If the len needs to be increased:
    if additional_elements > 0 {
        // Check if the new len is valid.
        if len > T::max_len() {
            return Err(Error::SizeLimitExceeded);
        }
        // Reserve additional capacity.
        self.reserve(additional_elements as usize)?;
    }

    let current_mem_allocator_len = self.mem_allocator.len();
    let required_mem_allocator_len =
        FamStructWrapper::<T>::mem_allocator_len(len).ok_or(Error::SizeLimitExceeded)?;
    // Update the len of the `mem_allocator`.
    // SAFETY: This is safe since enough capacity has been reserved.
    unsafe {
        self.mem_allocator.set_len(required_mem_allocator_len);
    }
    // Zero-initialize the additional elements if any.
    for i in current_mem_allocator_len..required_mem_allocator_len {
        // SAFETY: Safe as long as the trait is only implemented for POD. This is a requirement
        // for the trait implementation.
        self.mem_allocator[i] = unsafe { mem::zeroed() }
    }
    // Update the len of the underlying `FamStruct`.
    self.as_mut_fam_struct().set_len(len);

    // If the len needs to be decreased, deallocate unnecessary memory
    if additional_elements < 0 {
        self.mem_allocator.shrink_to_fit();
    }

    Ok(())
}

fn ensure_buffer_len(mut buffer: Vec<i32>, new_len: usize) -> Vec<i32> {
    if buffer.len() < new_len {
        // Previous data will be overwritten, so instead of resizing the
        // vector if it is too small, we might as well allocate a new one.
        if buffer.capacity() < new_len {
            buffer = Vec::with_capacity(new_len);
        }

        // We are going to fill the buffer anyway, so there is no point in
        // initializing it with default values. This does mean that there could
        // be garbage in the buffer, but that is not exposed, as the buffer is
        // only exposed if a frame has been decoded successfully, and hence the
        // entire buffer has been overwritten.
        unsafe { buffer.set_len(new_len); }
    } else {
        buffer.truncate(new_len);
    }
    buffer
}

pub fn force(this: &Lazy<T, F>) -> &T {
    // Safe because closure is guaranteed to be called at most once
    // so we only call `F` once, this also guarantees no race conditions
    this.cell.get_or_init(|| unsafe {
        match (*this.init.get()).take() {
            Some(f) => f(),
            None => unreachable_unchecked(),
        }
    })
}

pub fn from_rc<U, F>(rc: &Rc<U>, project: F) -> Self
where
    U: ?Sized,
    T: 'static,
    F: FnOnce(&U) -> &T,
{
    let projected = project(rc);
    // SAFETY: fn shouldn't be able to capture any local references
    // which should mean that the projection done by f is safe
    let projected = unsafe { NonNull::new_unchecked(projected as *const T as *mut T) };
    Self {
        rc: TypeErasedRc::new(rc.clone()),
        projected,
    }
}

